var e=JSON.parse(`[{"id":"L3_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"……좋습니다. 정리해 보죠.","JPN":"……いいでしょう。では、整理してみましょう。","ENG":"All right. Shall we?","TWN":"……好，來整理整理吧。"},"stage":{"bg":"MEETING_ROOM","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE"},{"id":"L4_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"성무 SI3E은 <color=#ffd34c>관리 거부 구역</color>에서 온 제보로 시작되었습니다.\xA0","JPN":"聖務SI3Eは<color=#ffd34c>管理拒否区域</color>からの情報提供で始まりました。\xA0","ENG":"A tip from the <color=#ffd34c>Anti-Administration Zone</color> initiated Sacred Mission SI3E.\xA0","TWN":"聖務SI3E是因從<color=#ffd34c>拒絕管理區域</color>來的獲報而開始的。"},"stage":{"bg":"MEETING_ROOM","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"심의회 멤버이니 관리 거부 구역에 대해서는 한 번쯤 들어 봤겠죠, 시스터 루퍼?","JPN":"審議会のメンバーですから、管理拒否区域については聞いたことがあるでしょう。シスタールーパー。","ENG":"You have probably heard of the Anti-Administration Zone as an Investigation Council member. Is that correct, Sister Looper?","TWN":"身為議會成員，你應該聽說過拒絕管理區域吧，洛珀姊妹？"},"stage":{"bg":"MEETING_ROOM","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"CINDY_VATICAN_NULL_SHORT","text":{"KOREA":"몰라, 그런 거.","JPN":"そんなの知らないね。","ENG":"Dunno.","TWN":"我不知道，"},"stage":{"bg":"MEETING_ROOM","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CINDY_VATICAN_NULL_SHORT","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"CINDY_VATICAN_NULL_SHORT","text":{"KOREA":"머리 쓰는 건 꺽다리 역할이거든. 내 일은 침식체들 천국 직행 버스 태워 보내기고.","JPN":"頭使うのはのっぽの仕事だから。アタシの仕事は侵食体を天国直行バスに乗せること。","ENG":"Long Legs was in charge of all the thinking. My job was to send those C.O.s to the doorstep of Heaven.","TWN":"動腦的事是高個子在負責的，我只負責將侵蝕體送上地獄直達列車。"},"stage":{"bg":"MEETING_ROOM","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CINDY_VATICAN_NULL_SHORT","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"CINDY_VATICAN_NULL_SHORT","text":{"KOREA":"그러니까 궁금한 게 있으면 꺽다리한테 묻든가.\xA0","JPN":"だから気になることあったらのっぽに聞いてよ。\xA0","ENG":"So if you have any questions, go ask him.\xA0","TWN":"所以你有什麼問題就去問高個子吧。"},"stage":{"bg":"MEETING_ROOM","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CINDY_VATICAN_NULL_SHORT","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"퍽이나 귀여운 후배님이로군요.","JPN":"本当に可愛い後輩ですね。","ENG":"You are not as cute as the Cardinal said.","TWN":"還真是可愛的新人呢。"},"stage":{"bg":"MEETING_ROOM","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_HATE"},"C":null,"R":null}}},{"id":"L12_1","type":"dialog","speaker":"CINDY_VATICAN_NULL_SHORT","text":{"KOREA":"왜? 불만 있어?","JPN":"何？　文句ある？","ENG":"What? You gotta problem with that?","TWN":"怎樣？有意見嗎？"},"stage":{"bg":"MEETING_ROOM","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_HATE"},"C":null,"R":{"char_id":"CINDY_VATICAN_NULL_SHORT","face":"UNIT_HATE"}}}},{"id":"L14_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"네. 당신이 썩 마음에 들지는 않습니다.","JPN":"はい。あなたをあまり好きになれなさそうです。","ENG":"Yes, I do. I do not really like you.","TWN":"有，我對你很有意見。"},"stage":{"bg":"MEETING_ROOM","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"하지만 당신은 사건의 주요 참고인입니다. 심문을 빨리 끝내고 싶으면 협조적인 태도로 임하세요.","JPN":"ですがあなたは事件の重要参考人です。早く審問を終わらせたいのなら、協力的な態度を見せてください。","ENG":"However, you are the primary witness in the case. If you want the interrogation to end swiftly, be cooperative.","TWN":"不過你是這次事件的主要證人，若想盡快結束審問，那就麻煩態度配合一點。"},"stage":{"bg":"MEETING_ROOM","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"CINDY_VATICAN_NULL_SHORT","text":{"KOREA":"쳇…….","JPN":"ちっ……","ENG":"Sheesh...","TWN":"嘖……"},"stage":{"bg":"MEETING_ROOM","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CINDY_VATICAN_NULL_SHORT","face":"UNIT_HATE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"관리 거부 구역이란 종교나 문화, 혹은 정치적 이유로 관리국이 중심인 대 침식전 체제를 거부한 구역을 지칭합니다.","JPN":"管理拒否区域とは宗教や文化、あるいは政治的な理由で、管理局が中心である対侵食戦体制を拒否した区域のことをいいます。","ENG":"The Anti-Administration Zone refers to areas that, for political, cultural, and religious reasons, have rejected the Anti-Corruption system that is centered on the Administration.","TWN":"拒絕管理區域，指的就是管理局因宗教、文化，或是政治因素，而拒絕反侵蝕體作戰的區域。"},"stage":{"bg":"MEETING_ROOM","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CINDY_VATICAN_NULL_SHORT","face":"UNIT_IDLE"}}}},{"id":"L20_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"작게는 원리주의 종교 공동체부터 크게는 국가까지 포함하는 개념이죠.","JPN":"原理主義の宗教共同体から、国家までを含む概念です。","ENG":"It is a broad concept that includes everything from fundamentalist religious communities to entire nations.","TWN":"這件事牽涉範圍小至整個宗教共同體，大至整個國家。"},"stage":{"bg":"MEETING_ROOM","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CINDY_VATICAN_NULL_SHORT","face":"UNIT_IDLE"}}}},{"id":"L21_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"이런 곳은 북방 합의체 같은 예외를 제외하면, 대부분 침식현상에 대응할 여력이 부족합니다.","JPN":"こういうところは北方合意体のような例外を除くと､ほとんどが侵食現象に対応しきれません｡","ENG":"However, most of these places lack the capacity to respond to the Counterside Effect, excluding Northern Union.","TWN":"這種地方，除非像是北方和議會這種例外，大部分是沒有餘力應付侵蝕現象的。"},"stage":{"bg":"MEETING_ROOM","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CINDY_VATICAN_NULL_SHORT","face":"UNIT_IDLE"}}}},{"id":"L22_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"그러나 성황청은 관리 거부 구역에서도 자원 봉사라는 형태로 침식 현상에 고통받는 이들을 돕고 있죠.","JPN":"ですが聖皇庁は管理拒否区域でもボランティアという形で侵食現象で苦しんでいる人たちを助けています｡","ENG":"However, the Holy Curia volunteers to help those suffering from the Counterside Effect in these Anti-Administration Zones.","TWN":"但聖皇廳在拒絕管理區域，也有以義工的形式幫助受侵蝕現象所苦的人對吧？"},"stage":{"bg":"MEETING_ROOM","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CINDY_VATICAN_NULL_SHORT","face":"UNIT_IDLE"}}}},{"id":"L23_1","type":"dialog","speaker":"CINDY_VATICAN_NULL_SHORT","text":{"KOREA":"아, 맞다. 그 말 들으니 기억나네.","JPN":"あ、そうだ。それ聞いたら思い出したよ。","ENG":"Oh, right. I remember now that you mention it.","TWN":"喔，對，聽你這麼說我想起來了。"},"stage":{"bg":"MEETING_ROOM","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CINDY_VATICAN_NULL_SHORT","face":"UNIT_IDLE"}}}},{"id":"L24_1","type":"dialog","speaker":"CINDY_VATICAN_NULL_SHORT","text":{"KOREA":"자원 봉사라고 뻥치고 이단들 사고 치나 감시하는 그거?\xA0","JPN":"ボランティアって嘘ついて、異端者を監視するあれだろ？\xA0","ENG":"The fake \\"volunteering\\" you do to monitor if those heretics aren't causing any trouble, right?\xA0","TWN":"義工只是幌子，實際上是監視異端有沒有惹事，你是指這個吧？"},"stage":{"bg":"MEETING_ROOM","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CINDY_VATICAN_NULL_SHORT","face":"UNIT_LAUGH"}}}},{"id":"L27_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"요점은 맞지만 단어 선정이 불경하군요.","JPN":"要点は合っていますが、単語選びが不敬ですね。","ENG":"Correct, but your choice of words is sacrilegious.","TWN":"你說的沒錯，只是字用不太合適。"},"stage":{"bg":"MEETING_ROOM","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_HATE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"CINDY_VATICAN_NULL_SHORT","text":{"KOREA":"방금 그 말이 불경해? 그 너풀거리는 치마는 민망해서 어떻게 입고 다니나 몰라.","JPN":"今の言葉が不敬なの？　あたしだったらそのひらひらしたスカートなんてきまり悪くて着れないけどなあ。","ENG":"What was so sacrilegious about that? What I don't get is how you can wear that fluttering skirt without feeling embarrassed.","TWN":"我剛的用詞不合適？你那身裙子飄呀飄的，那麼尷尬，我也不知道你怎麼敢穿？"},"stage":{"bg":"MEETING_ROOM","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CINDY_VATICAN_NULL_SHORT","face":"UNIT_LAUGH"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"어깨 위에 얹고 다니는 것도 꽤 너풀거리는 것 같습니다만.","JPN":"その肩の上にあるものも結構ひらひらしているようですが。","ENG":"I believe I recognize another fluttering thing. That thing between your shoulders, hmm?","TWN":"你的腦袋擱在脖子上也蠻飄的吧？"},"stage":{"bg":"MEETING_ROOM","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"든 게 없으니까요.","JPN":"何も入っていないからでしょうか。","ENG":"Because it's mostly filled with air.","TWN":"畢竟裡面很空沒裝什麼。"},"stage":{"bg":"MEETING_ROOM","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_PRIDE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"CINDY_VATICAN_NULL_SHORT","text":{"KOREA":"호오, 혀 좀 굴리는데. 언니.","JPN":"ほほう、結構やるじゃん。お姉さん。","ENG":"Ho-oh... Nice comeback, \\"Sister\\".","TWN":"哇喔，嘴巴很毒喔，這位姊姊。"},"stage":{"bg":"MEETING_ROOM","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CINDY_VATICAN_NULL_SHORT","face":"UNIT_LAUGH"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"자랑할 수준은 아닙니다. 본론으로 돌아가죠.","JPN":"自慢するほどではありません。本題に戻りましょう。","ENG":"It is nothing to brag about, and we must get back to the subject at hand.","TWN":"這沒什麼好說嘴的，我們回到正題吧。"},"stage":{"bg":"MEETING_ROOM","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"문명의 이기라는 건, 사실 모든 이들에게 공평하게 주어지진 않습니다.","JPN":"文明の利器というものは、実はすべての人に公平に与えられるものではありません。","ENG":"The benefits of civilization are not distributed equally.","TWN":"所謂文明的利器，並非對每個人都是公平的。"},"stage":{"bg":"MEETING_ROOM","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CINDY_VATICAN_NULL_SHORT","face":"UNIT_IDLE"}}}},{"id":"L37_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"차원 함선이 날아다니고 인공 지능이 사람을 대체해 가는 지금도, 지구 어딘가에는 외부와 고립된 채 살아가는 이들이 있죠.","JPN":"次元艦船が飛び交い、人工知能が人にとって代わりつつある今も、地球のどこかでは外部と断絶されたまま生きている人たちがいるのです。","ENG":"Even now, with dimensional ships flying around and AI replacing humans, there are still people on who are cut off from the rest of the world.","TWN":"在次元艦船到處飛，人工智慧逐漸取代人類的現代，在地球某處，還是有人過著與世隔絕的生活。"},"stage":{"bg":"MEETING_ROOM","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CINDY_VATICAN_NULL_SHORT","face":"UNIT_IDLE"}}}},{"id":"L38_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"그렇다면 그들에게 침식체는 어떤 존재일까요?","JPN":"だとしたら彼らにとって侵食体はどんな存在だと思いますか？","ENG":"What kind of existence would C.O.s be to those people?","TWN":"那對他們而言，侵蝕體是什麼樣的存在呢？"},"stage":{"bg":"MEETING_ROOM","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"CINDY_VATICAN_NULL_SHORT","face":"UNIT_IDLE"}}}},{"id":"L39_1","type":"dialog","speaker":"CINDY_VATICAN_NULL_SHORT","text":{"KOREA":"무섭겠지, 뭘.","JPN":"まあ、怖いかな。","ENG":"Scary stuff, I bet.","TWN":"當然是可怕的存在，嘖～"},"stage":{"bg":"MEETING_ROOM","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"CINDY_VATICAN_NULL_SHORT","face":"UNIT_IDLE"}}}},{"id":"L40_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"그래요. 그리고 원시시대에 불과 번개가 그랬듯 공포는 숭배로 이어지기도 합니다.","JPN":"そのとおりです。そして原始時代に火と稲妻がそうだったように、恐怖は崇拝に繋がったりもします。","ENG":"Exactly. Fear, like fire and lightning in primitive times, will lead to worship.","TWN":"沒錯，就像原始時代，人們會崇拜火和閃電是出於恐懼一樣。"},"stage":{"bg":"MEETING_ROOM","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CINDY_VATICAN_NULL_SHORT","face":"UNIT_IDLE"}}}},{"id":"L41_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"주님의 어린 양들이 그런 잘못된 길에 들지 않게 하는 것도 심의회의 성무 중 하나죠.","JPN":"主の子羊たちがそのような間違った道に進まないようにすることもまた審議会の聖務の一つです。","ENG":"As such, it is one of the Investigation Council's sacred duties to keep the Lord's lambs from wandering off course.","TWN":"保護天主的小羊不走錯路也是議會的聖務之一。"},"stage":{"bg":"MEETING_ROOM","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"CINDY_VATICAN_NULL_SHORT","face":"UNIT_IDLE"}}}},{"id":"L42_1","type":"dialog","speaker":"CINDY_VATICAN_NULL_SHORT","text":{"KOREA":"하여간 주는 것도 쥐뿔 없으면서 바라는 것만 많아요.","JPN":"まったく、主は何もくれないくせに要求ばっかりしてくるんだね。","ENG":"Ugh... They pay us pennies and ask so much from us.","TWN":"給那麼少，還要求東要求西的。"},"stage":{"bg":"MEETING_ROOM","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"CINDY_VATICAN_NULL_SHORT","face":"UNIT_HATE"}}}},{"id":"L44_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"……성무 SI3E도 같은 갈래에 속합니다.","JPN":"……聖務SI3Eも同じ系統です。","ENG":"Sacred Mission SI3E also falls into the same category.","TWN":"……聖務SI3E也是類似的概念。"},"stage":{"bg":"MEETING_ROOM","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_IDLE"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"캄파멘토 인근 깊은 숲. 어느 이름 없는 마을.","JPN":"カンパメント近くの深い森。とある名もなき村。","ENG":"In the depths of a forest nearby Campamento. In some nameless village.","TWN":"在坎帕門托附近的森林，有一個無名的村莊，"},"stage":{"bg":"MEETING_ROOM","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_IDLE"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"그 마을에서 머물던 성황청의 협력자는 당시 그 곳에 거대한 나무를 숭배하는 토테미즘 신앙이 있다고 했습니다.","JPN":"その村に泊まっていた聖皇庁の協力者は、当時そこに巨大な木を崇拝するトーテミズム信仰があると言いました。","ENG":"An ally of Holy Curia who lived there at the time reported that there was a totemist belief worshipping a large tree.","TWN":"根據滯留在當地的聖皇廳夥伴的說法，當時那個地方原本的信仰是崇拜巨木的圖騰崇拜。"},"stage":{"bg":"MEETING_ROOM","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_IDLE"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"하지만 언제부터인가 침식 현상 탓인지, 마을 사람들이 점점 이상해지기 시작했고…….","JPN":"ですがいつからか侵食現象のせいか、村人たちはどんどんおかしくなり始め……","ENG":"But, at some point, perhaps as a result of the Counterside Effect, the villagers began to act strangely...","TWN":"但不知從何時開始，或許是因為侵蝕現象的關係，村裡的人開始變得有點奇怪……"},"stage":{"bg":"MEETING_ROOM","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_IDLE"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"CINDY_VATICAN_NULL_SHORT","text":{"KOREA":"하하호호 손에 손 잡고 다 같이 죽었다?","JPN":"笑いながら手に手をとって一緒に死にでもした？","ENG":"What? You mean they held hands singing Kumbaya and killed themselves?","TWN":"哈哈呵呵，然後就一起手牽手死光光？"},"stage":{"bg":"MEETING_ROOM","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CINDY_VATICAN_NULL_SHORT","face":"UNIT_SURPRISE"}}}},{"id":"L1_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"아니요. 이 다음부터는 당신이 저보다 더 잘 알고 있을 겁니다.","JPN":"いいえ。次からはあなたの方がもっとよく知っているはずです。","ENG":"No. From this point on, you will know the details better than me.","TWN":"不，後面的事你應該比我更清楚。"},"stage":{"bg":"MEETING_ROOM","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CINDY_VATICAN_NULL_SHORT","face":"UNIT_SURPRISE"}}}},{"id":"L2_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"침식 증후군으로 발생할 수 있는 문제에 대비하기 위해, 제 9호 심의회와 철퇴 용병단이 파견되었으니까요.","JPN":"侵食症候群で発生する可能性がある問題に備えるため、第9号審議会と鉄槌傭兵団が派遣されましたから。","ENG":"To prevent any trouble from Corruption Syndrome, Investigation Council 9 and Mace Mercenary deployed to the area.","TWN":"為了防止侵蝕症候群可能帶來的問題，於是便派出第九議會和鐵鎚傭兵團。"},"stage":{"bg":"MEETING_ROOM","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"CINDY_VATICAN_NULL_SHORT","face":"UNIT_SURPRISE"}}}},{"id":"L3_1","type":"dialog","speaker":"CINDY_VATICAN_NULL_SHORT","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"MEETING_ROOM","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"CINDY_VATICAN_NULL_SHORT","face":"UNIT_IDLE"}}}},{"id":"L5_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"보고서에는 지원 요청을 받고 당신과 베네딕트가 급파됐다고 쓰여 있군요.","JPN":"報告書には支援要請を受け、あなたとベネディクトが急派されたと書いてありますね。","ENG":"According to the report, you and Benedict were dispatched in response to a request for assistance.","TWN":"而根據報告上的紀錄，在接到支援請求後，便立刻派遣你和本尼迪克特至當地。"},"stage":{"bg":"MEETING_ROOM","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"CINDY_VATICAN_NULL_SHORT","text":{"KOREA":"그래. 클로디아를 구하러 갔어. 잘 아네.","JPN":"そうだよ。クラウディアを助けに行ったんだ。よく知ってるね。","ENG":"Yeah. We went there to rescue Claudia. You did your homework.","TWN":"沒錯，我們是去救克勞迪婭的，看來你很清楚嘛。"},"stage":{"bg":"MEETING_ROOM","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CINDY_VATICAN_NULL_SHORT","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"하지만 오류가 있군요. 심의회는 각 호가 1개 조로 성무를 수행하게 되어 있습니다.","JPN":"ですが、おかしな点があります。通常、審議会は各号がひとつの班を構成して聖務を遂行するようになっています。","ENG":"However, there appears to be an error. Each Investigation Council carries out sacred missions by forming a group.","TWN":"但當中有個錯誤，議會各號都是以組為單位去執行聖務的，"},"stage":{"bg":"MEETING_ROOM","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"그런데 그 날은 넬슨 시스터만 파견되었어요.","JPN":"なのに、あの日はシスターネルソンだけが派遣されました。","ENG":"But on that day, Sister Nelson was dispatched alone.","TWN":"那天卻只有派尼爾森姊妹去。"},"stage":{"bg":"MEETING_ROOM","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"CINDY_VATICAN_NULL_SHORT","text":{"KOREA":"심의회는 항상 사람 부족하다고 징징거리잖아?","JPN":"審議会はいつも人手不足だって文句言ってるだろ？","ENG":"Don't you guys always whine about not having enough manpower or something?","TWN":"議會不是常常都嚷嚷著人手不夠嗎？"},"stage":{"bg":"MEETING_ROOM","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CINDY_VATICAN_NULL_SHORT","face":"UNIT_IDLE"}}}},{"id":"L12_1","type":"dialog","speaker":"CINDY_VATICAN_NULL_SHORT","text":{"KOREA":"꺽다리 생각에 클로디아 혼자 집행할 수 있을 줄 알았나 보지.","JPN":"のっぽはクラウディアが一人で執行できると思ったんじゃない？","ENG":"Maybe Long Legs thought that Claudia could do it on her own.","TWN":"可能高個子認為克勞迪婭一個人足以勝任吧？"},"stage":{"bg":"MEETING_ROOM","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CINDY_VATICAN_NULL_SHORT","face":"UNIT_IDLE"}}}},{"id":"L13_1","type":"dialog","speaker":"CINDY_VATICAN_NULL_SHORT","text":{"KOREA":"나랑 꺽다리는 그 때 근처에서 악마 들렸다고 설치는 녀석이랑 실랑이 중이었어.","JPN":"あの時、あたしとのっぽは、近所で悪魔に取りつかれたって騒ぐやつともめててさ。","ENG":"At the time, Long Legs and I were in a scuffle with a guy who claimed he is possessed of the devil.","TWN":"當時我和高個子正在對付一個被鬼附的傢伙。"},"stage":{"bg":"MEETING_ROOM","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CINDY_VATICAN_NULL_SHORT","face":"UNIT_IDLE"}}}},{"id":"L14_1","type":"dialog","speaker":"CINDY_VATICAN_NULL_SHORT","text":{"KOREA":"눈앞에다 전기톱 살랑살랑 흔들어 주니까 알아서 나았지만.","JPN":"目の前にチェーンソーを振ってやったらひとりでに治ったんだけど。","ENG":"But when I waved my chainsaw in front of his face, he finally shut up.","TWN":"只是當我拿著電鋸在他面前晃時，鬼就自己出去咧。"},"stage":{"bg":"MEETING_ROOM","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CINDY_VATICAN_NULL_SHORT","face":"UNIT_LAUGH"}}}},{"id":"L15_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"그럼 때마침 침식체가 출몰했던 것도 우연이라는 말씀이로군요.","JPN":"それでは、その時ちょうど侵食体が現れたのも偶然だったということですね。","ENG":"Then you are saying that the sudden appearance of C.O.s was just a coincidence?","TWN":"意思是侵蝕體在那時候出現只是巧合對吧？"},"stage":{"bg":"MEETING_ROOM","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"CINDY_VATICAN_NULL_SHORT","face":"UNIT_LAUGH"}}}},{"id":"L17_1","type":"dialog","speaker":"CINDY_VATICAN_NULL_SHORT","text":{"KOREA":"짜증나게 말 돌리지 마. 꺽다리랑 내가 짜고 클로디아를 보냈다고 의심하는 거잖아.","JPN":"話そらさないでよ。のっぽとアタシが仕組んで、クラウディアを送ったって疑ってるんでしょ？","ENG":"Will you stop beating around the bush? It's so annoying. You're suspecting Long Legs and me of sending Claudia out on her own, right?","TWN":"煩不煩，少在那邊話中有話，你現在就是懷疑我和高個子設計陷害克勞迪婭不是嗎！"},"stage":{"bg":"MEETING_ROOM","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CINDY_VATICAN_NULL_SHORT","face":"UNIT_SURPRISE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L18_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"아뇨. 기도문도 똑바로 못 외우는 꼬마 시스터가 그런 대범한 짓을 저질렀을 리가요.","JPN":"いいえ。祈祷文もきちんと覚えられないちびっこシスターが、そんな大胆なことをやらかすはずがありません。","ENG":"No. I doubt a little Sister like yourself, who cannot even recite her prayers, would dare do such a thing.","TWN":"不是，一個連祈禱文都不會背的小姊妹，怎麼可能有膽做這種事。"},"stage":{"bg":"MEETING_ROOM","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"뭐, 관리 거부 구역의 유일한 이교도 생존자라면, 얘기가 다를지도 모르겠습니다만.","JPN":"まあ、管理拒否区域に生存する唯一の異教徒なら、話が違うかも知れませんが。","ENG":"But if it were the sole survivor of a cult in the Anti-Administration Zone, it would paint a different picture.","TWN":"不過，若是拒絕管理區域裡唯一的異端倖存者，那或許不好說。"},"stage":{"bg":"MEETING_ROOM","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"CINDY_VATICAN_NULL_SHORT","text":{"KOREA":"말조심하지? 내 앞에서 그딴 소리 지껄이다 혼쭐난 처녀 총각만 열두 광주리에 가득이야.","JPN":"言葉に気をつけた方がいいんじゃない？　あたしの前でそんなこと言って、痛い目にあったやつが十二の籠いっぱいいるんだ。","ENG":"Watch your mouth! You know I got a dozen of basketfuls of idiots who said that to me, right?","TWN":"說話小心點！你知道我教訓過多少對我說過這種話的人嗎？都已經可以裝滿12個籃子！"},"stage":{"bg":"MEETING_ROOM","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CINDY_VATICAN_NULL_SHORT","face":"UNIT_HATE"}}}},{"id":"L23_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"조사관인 저를 공격하면 당신의 보호자 격인 시스터 넬슨의 입장도 곤란해질 겁니다.","JPN":"調査官である私を攻撃すれば、あなたの保護者であるシスターネルソンの立場が悪くなりますよ。","ENG":"Hurting an investigator will only make things worse for your guardian, Sister Nelson.","TWN":"你要是攻擊身為調查官的我，你的監護人尼爾森姊妹應該會很為難吧？"},"stage":{"bg":"MEETING_ROOM","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CINDY_VATICAN_NULL_SHORT","face":"UNIT_HATE"}}}},{"id":"L24_1","type":"dialog","speaker":"CINDY_VATICAN_NULL_SHORT","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"MEETING_ROOM","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CINDY_VATICAN_NULL_SHORT","face":"UNIT_DESPAIR"}}}},{"id":"L26_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"현장에 급파된 당신은 그 숲에서 무엇을 봤죠?","JPN":"現場に急派されたあなたは、あの森で何を見たのですか？","ENG":"After you were dispatched to the forest, what did you see?","TWN":"你被派到當地後看到什麼？"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"CINDY_VATICAN_NULL_SHORT","text":{"KOREA":"쳇…….","JPN":"ちっ……","ENG":"Sheesh...","TWN":"嘖……"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CINDY_VATICAN_NULL_SHORT","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"CINDY_VATICAN_NULL_SHORT","text":{"KOREA":"녀석들이 그 숲에서 우리를 기다리고 있었어.","JPN":"やつらがあの森であたしたちを待ってたんだ。","ENG":"They were waiting for us in the forest.","TWN":"那些傢伙就在森林裡等我們。"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CINDY_VATICAN_NULL_SHORT","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"기다리고 있었다? 침식체 말인가요?","JPN":"待っていた？　侵食体のことですか？","ENG":"Waiting for you? Do you mean the C.O.s?","TWN":"等你們？你說侵蝕體嗎？"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"CINDY_VATICAN_NULL_SHORT","face":"UNIT_IDLE"}}}},{"id":"L32_1","type":"dialog","speaker":"CINDY_VATICAN_NULL_SHORT","text":{"KOREA":"아니. 그것들이 얌전히 기다리겠어? 손님이라면 환장해서 튀어나오는데.","JPN":"いや。あいつらは大人しく待ったりしない。客が来れば大喜びで飛び出てくるし。","ENG":"No. Why would they be waiting for us? They would run towards us like crazy!","TWN":"不是，你覺得侵蝕體有那麼乖嗎？應該會一股腦兒撲上來吧？"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"CINDY_VATICAN_NULL_SHORT","face":"UNIT_IDLE"}}}},{"id":"L34_1","type":"dialog","speaker":"CINDY_VATICAN_NULL_SHORT","text":{"KOREA":"그 아저씨들이었어. 철퇴 뭐시기.","JPN":"あのおっさんたちだよ。鉄槌なんとか。","ENG":"It was the mercenary guys. The Mace whatchamacallit.","TWN":"是什麼鐵鎚的那些大叔。"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CINDY_VATICAN_NULL_SHORT","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};